import com.scbank.process.api.fw.core.utils.StringUtils;
import com.scbank.process.api.fw.session.ISessionContextManager;
import com.scbank.process.api.svc.shared.constants.PRCSharedConstants;
import com.wizvera.WizveraConfig;
import com.wizvera.crypto.CertUtil;
import com.wizvera.service.DelfinoServiceException;
import com.wizvera.service.FintechSignVerifier;
import com.wizvera.service.SignVerifier;
import com.wizvera.service.SignVerifierResult;

import jakarta.annotation.PostConstruct;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;

@Slf4j
@RequiredArgsConstructor
@SharedComponent(name = "토스인증서 전자서명인증서 검증", description = "토스인증서 전자서명인증서 검증", author = "이완주")
public class FinTechCertVerifyComponent {

    private final ISessionContextManager SessionManager;

    private HashMap<String, String> DUMMY_MULTI = new HashMap<String, String>();
    private HashMap<String, String> DUMMY_SINGLE = new HashMap<String, String>();

    @Value("${delfino.config.path:}")
    private String configPath;

    @PostConstruct
    @ComponentOperation(name = "test", description = "test", author = "이완주")
    public void test() {
        if (!RunMode.LOCAL.equals(RuntimeContext.getRunMode()))
            return;
        this.DUMMY_MULTI.put("kakaotalk",
                "|||");
        this.DUMMY_MULTI.put("naver2",
                "|||");
        this.DUMMY_MULTI.put("toss",
                "|||");
        this.DUMMY_SINGLE.put("kakaotalk",
                "");
        this.DUMMY_SINGLE.put("naver2",
                "");
        this.DUMMY_SINGLE.put("toss",
                "");
        this.DUMMY_SINGLE.put("pass",
                "");
    }

    /**
     * 전자서명 검증
     *
     * @param isMultiSign
     * @param signData
     * @return
     * @throws PRCServiceException
     */
    @ComponentOperation(name = "전자서명 검증", description = "전자서명 검증", author = "이완주")
    public HashMap<String, Object> signVerify(String isMultiSign, String signData) throws PRCServiceException {
        log.debug("(●'◡'●) 핀테크인증서 전자서명 검증 시작 isMultiSign={}, signData={}", isMultiSign, signData);

        // 환경설정 경로 지정 필요할경우
        WizveraConfig delfinoConfig = null;
        try {
            delfinoConfig = new WizveraConfig(configPath);
        } catch (IOException|IllegalStateException e) {
            log.error("delfino.properties 설정파일 찾지 못해 기본생성자로 SignVerifier를 생성함");
        }

        // 로컬테스트용
        if (RunMode.LOCAL.equals(RuntimeContext.getRunMode())) {
            signData = "Y".equals(isMultiSign) ? DUMMY_MULTI.get("toss") : DUMMY_SINGLE.get("toss");
        }

        if (signData == null || "".equals(signData))
            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다. [1]");

        // ======================================================
        // 1. CI확인
        // ======================================================
        String userCI = SessionManager.isLogin() ? SessionManager.getLoginValue("USER_CI_INFO", String.class)
                : SessionManager.getGlobalValue("USER_CI_INFO", String.class);
        if (!RunMode.LOCAL.equals(RuntimeContext.getRunMode())) {
            if (userCI == null)
                throw new PRCServiceException("PRCCMMVPCG_0003", "본인인증이 정상적으로 처리되지 않았습니다. 처음부터 다시 신청해주시길 바랍니다. [1]");
        }

        // ======================================================
        // 2. 서명데이터 파싱
        // ======================================================
        String provider = "";
        try {
            if ("Y".equals(isMultiSign)) {
                if (FintechSignVerifier.isFintechMultiSignResult(signData)) { // signType == MULTI || signType ==
                                                                              // PDF_MULTI
                    JSONObject signDataObj = new JSONObject(signData);
                    provider = (String) signDataObj.get("provider");
                    log.debug("(❁´◡`❁) 핀테크인증서 provider={}", provider);
                    log.debug("(❁´◡`❁) 핀테크인증서 signData={}", signData);
                }

            } else {
                if (FintechSignVerifier.isFintechSignResult(signData)) { // signType != null
                    JSONObject signDataObj = new JSONObject(signData);
                    provider = (String) signDataObj.get("provider");
                    log.debug("핀테크인증서 provider={}", provider);
                    log.debug("핀테크인증서 signData={}", signData);
                }
            }
        } catch (Exception e) {
            log.error(e.getMessage());
            throw new PRCServiceException("PRCCMM0003", "전자서명 데이터 처리중 에러가 발생하였습니다.");
        }

        // ======================================================
        // 3. 서명데이터 검증
        // ======================================================
        SignVerifier signVerifier = new SignVerifier(delfinoConfig); // 서명검증 객체
        SignVerifierResult signVerifierResult = null; // 서명검증 결과
        String MULTI_SIGN_Delimiter = "\\|";
        String pkcs7SignedData = "";
        String originSignedRawData = "";
        String signedRawData = "";
        HashMap<String, Object> resultMap = new HashMap<String, Object>();
        try {

            if ("Y".equals(isMultiSign)) { // 복수 전자서명
                if (FintechSignVerifier.isFintechMultiSignResult(signData)) {
                    FintechSignVerifier fintechSignVerifier = new FintechSignVerifier();
                    SignVerifierResult[] multiSignVerifierResult = fintechSignVerifier.verifyPKCS(signData);

                    String pkcs7PdfSignData = ""; // PDF Hash 사인데이터

                    // 데이터 원문
                    String tempInputPlainText = SessionManager.getGlobalValue("finTechSignPlainText", String.class);
                    String[] inputPlainText = tempInputPlainText.split(MULTI_SIGN_Delimiter);

                    for (int i = 0; i < multiSignVerifierResult.length; i++) {
                        signVerifierResult = multiSignVerifierResult[i];

//                        try {
//                            if (i == 0) {
//                                if (signVerifierResult != null) {
//                                    boolean isSaveTxInfo = signVerifierResult.saveTxInfo("", "MULTI");
//                                    log.debug("(❁´◡`❁) 핀테크인증서 Multi isSaveTxInfo :: [ " + isSaveTxInfo + " ]");
//                                }
//                            }
//                        } catch (Exception e) {
//                            log.error(e.getMessage());
//                        }
                        
                        if(signVerifierResult != null) {
	                        pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
	                        originSignedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터
	                        signedRawData = signVerifierResult.getSignedRawData(); // 서명원문 데이터
                        }
                        log.debug("(❁´◡`❁) 핀테크인증서 getPKCS7SignedData={}", pkcs7SignedData);
                        log.debug("(❁´◡`❁) 핀테크인증서 getOriginSignedRawData={}", originSignedRawData);
                        log.debug("(❁´◡`❁) 핀테크인증서 getSignedRawData={}", signedRawData);

                        if (StringUtils.isEmpty(originSignedRawData) || StringUtils.isEmpty(pkcs7SignedData) || StringUtils.isEmpty(signedRawData)) {
                            throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
                        }

                        // 원문과 복호화값 비교
                        log.debug("(❁´◡`❁) 핀테크인증서 inputPlainText={}", inputPlainText[i]);
                        if (originSignedRawData.equals(inputPlainText[i]) == false) {
                            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다. [2]");
                        }

                        if (i > 0) {
                            pkcs7PdfSignData += pkcs7SignedData;

                            if (i < (multiSignVerifierResult.length - 1)) {
                                pkcs7PdfSignData += MULTI_SIGN_Delimiter;
                            }
                        }
                    }

                    // 전문사용 전자서명 거래 데이터 세팅을 위해 첫데이터결과 재설정
                    signVerifierResult = multiSignVerifierResult[0];

                    // 인증서 소유자 본인확인
                    if (!RunMode.LOCAL.equals(RuntimeContext.getRunMode())) {
                        log.debug("(❁´◡`❁) 핀테크인증서 CI검증 시작 getCi={}", signVerifierResult.getCi());

                        boolean isVerifiableCi = signVerifierResult.isVerifiableCi();
                        if (isVerifiableCi) {
                            boolean verifyCi = signVerifierResult.verifyCi(userCI);
                            log.debug("(❁´◡`❁) 핀테크인증서 verifyCi={}", verifyCi);

                            if (verifyCi == false) {
                                throw new PRCServiceException("PRCCMMVPCG_0005", "본인인증에 실패했습니다. 본인인증 사용자와 핀테크 인증서를 제출한 사용자가 다릅니다.");
                            }
                        } else {
                            throw new PRCServiceException("PRCCMMVPCG_0003", "본인인증이 정상적으로 처리되지 않았습니다. 처음부터 다시 신청해주시길 바랍니다. [2]");
                        }
                    }

                    resultMap.put("pkcs7PdfSignData", pkcs7PdfSignData);
                    resultMap.put("pkcs7SignedData", multiSignVerifierResult[0].getPKCS7SignedData()); // 거래데이터 +
                                                                                                       // PDFHash

                } else {

                    String[] pkcs7Array = signData.split(MULTI_SIGN_Delimiter);
                    SignVerifierResult[] signVerifierResultArray = new SignVerifierResult[pkcs7Array.length];
                    String pkcs7 = null;

                    String pkcs7PdfSignData = ""; // PDF Hash 사인데이터

                    for (int i = 0; i < pkcs7Array.length; i++) {
                        pkcs7 = pkcs7Array[i];
                        signVerifierResultArray[i] = signVerifier.verifyPKCS7WithoutCertValidation(pkcs7);
                        signVerifierResult = signVerifierResultArray[i];

//                        try {
//                            if (i == 0) {
//                                if (signVerifierResult != null) {
//                                    boolean isSaveTxInfo = signVerifierResult.saveTxInfo("", "MULTI");
//                                    log.debug("(❁´◡`❁) 핀테크인증서 Multi isSaveTxInfo :: [ " + isSaveTxInfo + " ]");
//                                }
//                            }
//                        } catch (Exception e) {
//                            log.error(e.getMessage());
//                        }
                        pkcs7SignedData = signVerifierResult != null ? signVerifierResult.getPKCS7SignedData() : StringUtils.EMPTY; // PKCS7 데이터
                        originSignedRawData = signVerifierResult != null ? signVerifierResult.getOriginSignedRawData() : StringUtils.EMPTY; // 원본 전자서명 데이터
                        signedRawData = signVerifierResult != null ? signVerifierResult.getSignedRawData(): StringUtils.EMPTY; // 서명원문 데이터

                        log.debug("(❁´◡`❁) 핀테크인증서 getPKCS7SignedData={}", pkcs7SignedData);
                        log.debug("(❁´◡`❁) 핀테크인증서 getOriginSignedRawData={}", originSignedRawData);
                        log.debug("(❁´◡`❁) 핀테크인증서 getSignedRawData={}", signedRawData);

                        // kakaotalk 는 다른 사설인증서 데이터와 구조가 달라 추가 처리
                        originSignedRawData = getKakaotalkOrgSignData(originSignedRawData);
                        signedRawData = getKakaotalkOrgSignData(signedRawData);

                        if (StringUtils.isEmpty(originSignedRawData) || StringUtils.isEmpty(pkcs7SignedData)
                                || StringUtils.isEmpty(signedRawData)) {
                            throw new PRCServiceException("PRCCMMVPCG_0002",
                                    "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
                        }

                        // pdfSignedData 구성
                        if (i > 0) {
                            pkcs7PdfSignData += pkcs7SignedData;

                            if (i < (signVerifierResultArray.length - 1)) {
                                pkcs7PdfSignData += MULTI_SIGN_Delimiter;
                            }
                        }
                    }

                    // 전문사용 전자서명 거래 데이터 세팅을 위해 첫데이터결과 재설정
                    signVerifierResult = signVerifierResultArray[0];

                    resultMap.put("pkcs7PdfSignData", pkcs7PdfSignData);
                    resultMap.put("pkcs7SignedData", signVerifierResultArray[0].getPKCS7SignedData()); // 거래데이터 + PDF
                                                                                                       // Hash
                }

            } else { // 단건 검증

                if (FintechSignVerifier.isFintechSignResult(signData)) {
                    signVerifierResult = signVerifier.verifyPKCS7(signData, SignVerifier.CERT_STATUS_CHECK_TYPE_NONE);

//                    try {
//                        if (signVerifierResult != null) {
//                            boolean isSaveTxInfo = signVerifierResult.saveTxInfo("", "SIMPLE");
//                            log.debug("핀테크인증서 Multi isSaveTxInfo :: [ " + isSaveTxInfo + " ]");
//                        }
//                    } catch (Exception e) {
//                        log.error(e.getMessage());
//                    }

                    // 데이터 원문
                    String inputPlainText = SessionManager.getGlobalValue("finTechSignPlainText", String.class);

                    if(signVerifierResult != null) {
                        pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
                        originSignedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터
                        signedRawData = signVerifierResult.getSignedRawData(); // 서명원문 데이터
                    }

                    log.debug("핀테크인증서 getPKCS7SignedData={}", pkcs7SignedData);
                    log.debug("핀테크인증서 getOriginSignedRawData={}", originSignedRawData);
                    log.debug("핀테크인증서 getSignedRawData={}", signedRawData);

                    if (StringUtils.isEmpty(originSignedRawData) || StringUtils.isEmpty(pkcs7SignedData)
                            || StringUtils.isEmpty(signedRawData)) {
                        throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
                    }

                    // 원문과 복호화값 비교
                    log.debug("핀테크인증서 inputPlainText={}", inputPlainText);
                    if (originSignedRawData.equals(inputPlainText) == false) {
                        throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다. [2]");
                    }

                    // 인증서 소유자 본인확인
                    if (!RunMode.LOCAL.equals(RuntimeContext.getRunMode())) {
                        log.debug("핀테크인증서 CI검증 시작 getCi={}", signVerifierResult.getCi());

                        boolean isVerifiableCi = signVerifierResult.isVerifiableCi();
                        if (isVerifiableCi) {
                            boolean verifyCi = signVerifierResult.verifyCi(userCI);
                            log.debug("핀테크인증서 verifyCi={}", verifyCi);

                            if (verifyCi == false) {
                                throw new PRCServiceException("PRCCMMVPCG_0005",
                                        "본인인증에 실패했습니다. 본인인증 사용자와 핀테크 인증서를 제출한 사용자가 다릅니다.");
                            }
                        } else {
                            throw new PRCServiceException("PRCCMMVPCG_0003",
                                    "본인인증이 정상적으로 처리되지 않았습니다. 처음부터 다시 신청해주시길 바랍니다. [2]");
                        }
                    }

                } else {
                    signVerifierResult = signVerifier.verifyPKCS7WithoutCertValidation(signData);

//                    try {
//                        if (signVerifierResult != null) {
//                            boolean isSaveTxInfo = signVerifierResult.saveTxInfo("", "SIMPLE");
//                            log.debug("핀테크인증서 Multi isSaveTxInfo :: [ " + isSaveTxInfo + " ]");
//                        }
//                    } catch (Exception e) {
//                        log.error(e.getMessage());
//                    }
                    if(signVerifierResult != null) {
                    	pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
                    	originSignedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터
                    	signedRawData = signVerifierResult.getSignedRawData(); // 서명원문 데이터
                    }

                    log.debug("핀테크인증서 getPKCS7SignedData={}", pkcs7SignedData);
                    log.debug("핀테크인증서 getOriginSignedRawData={}", originSignedRawData);
                    log.debug("핀테크인증서 getSignedRawData={}", signedRawData);

                    // kakaotalk 는 다른 사설인증서 데이터와 구조가 달라 추가 처리
                    originSignedRawData = getKakaotalkOrgSignData(originSignedRawData);
                    signedRawData = getKakaotalkOrgSignData(signedRawData);
                }

                if (StringUtils.isEmpty(originSignedRawData) || StringUtils.isEmpty(pkcs7SignedData) || StringUtils.isEmpty(signedRawData)) {
                    throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
                }

                resultMap.put("pkcs7SignedData", pkcs7SignedData); // 거래데이터

            }
        } catch (DelfinoServiceException e) {
            if ("ko".equalsIgnoreCase(LocaleContextHolder.getLocale().getLanguage())) {
                throw new PRCServiceException("FINERR_" + e.getErrorCode(), e.getErrorUserMessage());
            } else {
                throw new PRCServiceException("FINERR_" + e.getErrorCode(),
                        e.getErrorUserMessage(com.wizvera.service.util.ErrorConvert.LOCALE_EN));
            }

        }

        // ======================================================
        // 4. 인증서 검증
        // ======================================================
        if(signVerifierResult == null)
        	throw new PRCServiceException("INI301", "정상적인 인증서가 아닙니다.(Code:001)");
        	
        X509Certificate userCert = signVerifierResult.getSignerCertificate();
        
        if (userCert == null)
            throw new PRCServiceException("INI301", "정상적인 인증서가 아닙니다.(Code:001)");

        String certSerial = CertUtil.getSerialDecimal(userCert); // 인증서시리얼(10진수)

        if (StringUtils.isEmpty(certSerial)) {
            throw new PRCServiceException("PRCCMMVPCG_0010", "전달된 핀테크인증 전자서명 데이터 검증에 실패하였습니다.");
        }

        // ======================================================
        // 5. 전문거래 전자서명 검증시 사용되는 전자서명값 설정
        // ======================================================
        String orgData = signVerifierResult.getSignedRawData(); // 서명원문
        orgData = getKakaotalkOrgSignData(orgData);

        SessionManager.setGlobalValue(PRCSharedConstants.SIGN_ORG_DATA_NAME, orgData);
        SessionManager.setGlobalValue(PRCSharedConstants.SIGN_DATA_NAME, pkcs7SignedData);

        log.debug("(●'◡'●) SIGN_ORG_DATA_NAME={}", orgData);
        log.debug("(●'◡'●) SIGN_DATA_NAME={}", signData);

        SessionManager.setGlobalValue(PRCSharedConstants.SIGN_SUCCESS_CODE, "0000");

        resultMap.put("returnCode", "0000");
        resultMap.put("userCert", userCert);
        resultMap.put("provider", provider);
        resultMap.put("certSerial", certSerial);
        log.debug("(●'◡'●) 핀테크 인증서 전자서명 검증 완료 resultMap={}", resultMap.toString());
        return resultMap;

    }

    /**
     * 본인인증 검증
     *
     * @param signData
     * @return
     * @throws PRCServiceException
     */
    @ComponentOperation(name = "본인인증 검증", description = "본인인증 검증", author = "이완주")
    public HashMap<String, Object> authVerify(String signData) throws PRCServiceException {
        log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 본인인증 검증 시작  signData={}", signData);

        // 환경설정 경로 지정 필요할경우
        WizveraConfig delfinoConfig = null;
        try {
            delfinoConfig = new WizveraConfig(configPath);
        } catch (IOException|IllegalStateException e) {
            log.error("delfino.properties 설정파일 찾지 못해 기본생성자로 SignVerifier를 생성함");
        }

        if (signData == null || "".equals(signData))
            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다.");

        // ======================================================
        // 1. CI확인
        // ======================================================
        String userCI = SessionManager.isLogin() ? SessionManager.getLoginValue("USER_CI_INFO", String.class)
                : SessionManager.getGlobalValue("USER_CI_INFO", String.class);
        if (!RunMode.LOCAL.equals(RuntimeContext.getRunMode())) {
            if (userCI == null)
                throw new PRCServiceException("PRCCMMVPCG_0003", "본인인증이 정상적으로 처리되지 않았습니다. 처음부터 다시 신청해주시길 바랍니다. [1]");
        }

        // ======================================================
        // 2. 서명데이터 파싱
        // ======================================================
        String provider = "";
        try {
            if (FintechSignVerifier.isFintechSignResult(signData)) { // signType != null
                JSONObject signDataObj = new JSONObject(signData);
                provider = (String) signDataObj.get("provider");

                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 isFintechSignResult provider={}", provider);
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 isFintechSignResult signData={}", signData);
            }
        } catch (Exception e) {
            log.error(e.getMessage());
            throw new PRCServiceException("PRCCMM0003", "전자서명 데이터 처리중 에러가 발생하였습니다.");
        }

        // ======================================================
        // 3. 서명데이터 검증
        // ======================================================
        SignVerifier signVerifier = new SignVerifier(delfinoConfig); // 서명검증 객체
        SignVerifierResult signVerifierResult = null; // 서명검증 결과
        String pkcs7SignedData = "";
        String originSignedRawData = "";
        String signedRawData = "";
        HashMap<String, Object> resultMap = new HashMap<String, Object>();

        try {
            if (FintechSignVerifier.isFintechSignResult(signData)) {
                signVerifierResult = signVerifier.verifyPKCS7(signData, SignVerifier.CERT_STATUS_CHECK_TYPE_NONE);

//                try {
//                if (signVerifierResult == null) {
//                	throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
//                        boolean isSaveTxInfo = signVerifierResult.saveTxInfo("", "AUTH2");
//                        log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 authVerify1 signVerifierResult isSaveTxInfo :: [ " + isSaveTxInfo + " ]");
//                }
//                } catch (Exception e) {
//                    log.error(e.getMessage());
//                }
                if(signVerifierResult != null) {
                	pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
                    originSignedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터
                    signedRawData = signVerifierResult.getSignedRawData(); // 서명원문 데이터
                }

                // naver는 getOriginSignedRawData() 시 '본인인증' 고정값으로 설정되어 내려온다
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getProvider={}", provider);
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getPKCS7SignedData={}", pkcs7SignedData);
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getOriginSignedRawData={}", originSignedRawData);
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getSignedRawData={}", signedRawData);

                if (StringUtils.isEmpty(originSignedRawData) || StringUtils.isEmpty(pkcs7SignedData) || StringUtils.isEmpty(signedRawData)) {
                    throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
                }

                // 인증서 소유자 본인확인
                if (!RunMode.LOCAL.equals(RuntimeContext.getRunMode())) {
                    log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 CI검증 시작 getCi={}", signVerifierResult.getCi());

                    boolean isVerifiableCi = signVerifierResult.isVerifiableCi();
                    if (isVerifiableCi) {
                        boolean verifyCi = signVerifierResult.verifyCi(userCI);
                        log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 verifyCi={}", verifyCi);

                        if (verifyCi == false) {
                            throw new PRCServiceException("PRCCMMVPCG_0005",
                                    "본인인증에 실패했습니다. 본인인증 사용자와 핀테크 인증서를 제출한 사용자가 다릅니다.");
                        }
                    } else {
                        throw new PRCServiceException("PRCCMMVPCG_0003",
                                "본인인증이 정상적으로 처리되지 않았습니다. 처음부터 다시 신청해주시길 바랍니다. [2]");
                    }
                }
            } else {
                signVerifierResult = signVerifier.verifyPKCS7WithoutCertValidation(signData);

                if(signVerifierResult != null) {
                	pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
                    originSignedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터
                    signedRawData = signVerifierResult.getSignedRawData(); // 서명원문 데이터
                }

                // naver는 getOriginSignedRawData() 시 '본인인증' 고정값으로 설정되어 내려온다
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getProvider={}", provider);
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getPKCS7SignedData={}", pkcs7SignedData);
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getOriginSignedRawData={}", originSignedRawData);
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 getSignedRawData={}", signedRawData);

                // kakaotalk 는 다른 사설인증서 데이터와 구조가 달라 추가 처리
                originSignedRawData = getKakaotalkOrgSignData(originSignedRawData);
                signedRawData = getKakaotalkOrgSignData(signedRawData);

                if (StringUtils.isEmpty(originSignedRawData) || StringUtils.isEmpty(pkcs7SignedData) || StringUtils.isEmpty(signedRawData)) {
                    throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
                }
            }

            resultMap.put("pkcs7SignedData", pkcs7SignedData); // 거래 데이터

            // ======================================================
            // 4. 인증서 검증
            // ======================================================

            // 사설인증서 시리얼 번호 추출
            if(signVerifierResult == null) {  throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다."); }
            X509Certificate userCert = signVerifierResult.getSignerCertificate(); // 사용자인증서
            CertificateHelper certHelper = new CertificateHelper(userCert);
            String certSerial = certHelper.getSerialDecimal(); // 인증서시리얼(10진수)
            String certSerialHex = certHelper.getSerialHex(); // 인증서시리얼(16진수) 0A10

            if (StringUtils.isEmpty(certSerial)) {
                throw new PRCServiceException("PRCCMMVPCG_0010", "전달된 핀테크인증 전자서명 데이터 검증에 실패하였습니다.");
            }

            // 인증서 유효기간
            java.text.DateFormat myDate = new java.text.SimpleDateFormat("yyyy-MM-dd hh:mm ss");
            String certBefore = new java.text.SimpleDateFormat("yyyy-MM-dd HH:mm:ss").format(userCert.getNotBefore()); // 인증서유효기간:시작일
            String certAfter = new java.text.SimpleDateFormat("yyyy-MM-dd HH:mm:ss").format(userCert.getNotAfter()); // 인증서유효기간:종료일
            java.util.Date currentTime = new java.util.Date();// 현재 시간
            int dateformat = (int) ((userCert.getNotAfter().getTime() - currentTime.getTime()) / (24 * 60 * 60 * 1000));

            log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 인증서 정보 인증서 일련번호 10진수 {} 16진수 {}", certSerial, certSerialHex);
            log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 인증서 정보 인증서 유효기간 발급기간 {} ~ {}", certBefore, certAfter);
            log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 현재시간 {}", myDate.format(currentTime));
            log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 고객님의 인증서는 {}일 후에 만료가 됩니다", dateformat);

            resultMap.put("returnCode", "0000");
            resultMap.put("userCert", userCert);
            resultMap.put("provider", provider);
            resultMap.put("certSerial", certSerial);
            log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 검증 완료하였습니다");

        } catch (DelfinoServiceException e) {
            log.error("핀테크인증서 ErrorCode {}", e.getErrorCode());
            log.error("핀테크인증서 ErrorMsg {}", e.getErrorUserMessage());
            log.error("핀테크인증서 ErrorMsg {}", e.getMessage());

            throw new PRCServiceException(Integer.toString(e.getErrorCode()), e.getErrorUserMessage());
        }

        return resultMap;
    }

    /**
     * kakaotalk signedData 의 경우 content 내부의 데이터를 리턴
     */
    private String getKakaotalkOrgSignData(String orgSignData) {
        String parseOrgSignData = "";

        try {
            JSONObject tempOrgData1 = new JSONObject(orgSignData);
            if (tempOrgData1.get("data") != null) {
            	JSONObject tempOrgData2 = new JSONObject(tempOrgData1.get("data").toString());
                parseOrgSignData = tempOrgData2.get("content").toString();
            } else {
                parseOrgSignData = orgSignData;
            }
            return parseOrgSignData;
        } catch (Exception e) {
            return orgSignData;
        }
    }

    /**
     * 핀테크 본인인증
     *
     * @param delfinoNonce
     * @param dataType     (L : 로그인, S : 전자서명, A : 본인인증)
     * @param vpcgData
     * @param userId
     * @return
     * @throws PRCServiceException
     */
    @ComponentOperation(name = "핀테크 본인인증", description = "핀테크 본인인증", author = "이완주")
    public HashMap<String, Object> authVerify(String delfinoNonce, String dataType, String vpcgData, String userId)
            throws PRCServiceException {
        log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 본인인증 검증 시작");

        // 환경설정 경로 지정 필요할경우
        WizveraConfig delfinoConfig = null;
        try {
            delfinoConfig = new WizveraConfig(configPath);
        } catch (IOException|IllegalStateException e) {
            log.error("delfino.properties 설정파일 찾지 못해 기본생성자로 SignVerifier를 생성함");
        }

        HashMap<String, Object> resultMap = null;

        if (dataType == null || "".equalsIgnoreCase(dataType) || !"A".equalsIgnoreCase(dataType))
            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다.");

        if (vpcgData == null || "".equalsIgnoreCase(vpcgData))
            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다.");

        log.debug("<<<<<<<<<<<<<<<<< authVerify dataType={}", dataType);
        log.debug("<<<<<<<<<<<<<<<<< authVerify vpcgData={}", vpcgData);
        log.debug("<<<<<<<<<<<<<<<<< authVerify delfinoNonce {} ", delfinoNonce);

        try {
            SignVerifier signVerifier = new SignVerifier(delfinoConfig); // 서명검증 객체 (Veraport-CG LIB)
            SignVerifierResult signVerifierResult = null; // 서명검증 결과 객체 (Veraport-CG LIB)

            // ======================================================
            // 1. 서명데이터 검증
            // ======================================================
            signVerifierResult = signVerifier.verifyPKCS7WithNonce(vpcgData, delfinoNonce, SignVerifier.CERT_STATUS_CHECK_TYPE_NONE);

            if (signVerifierResult == null) {
            	throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
//                boolean isSaveTxInfo = signVerifierResult.saveTxInfo(userId, "AUTH");
//                log.info("<<<<<<<<<<<<<<<<< authVerify isSaveTxInfo {}", isSaveTxInfo);
            }

//            log.debug("<<<<<<<<<<<<<<<<< authVerify getProvider :: {}", signVerifierResult.getProvider());
//            log.debug("<<<<<<<<<<<<<<<<< authVerify getPKCS7SignedData :: {}", signVerifierResult.getPKCS7SignedData());
//            log.debug("<<<<<<<<<<<<<<<<< authVerify getSignedRawData :: {}", signVerifierResult.getSignedRawData());

            String pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
            String signedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터

            if (StringUtils.isEmpty(signedRawData) || StringUtils.isEmpty(pkcs7SignedData)) {
                throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
            }

            String originSignedRawData = delfinoNonce;

            // ======================================================
            // 2. provider 확인
            // ======================================================
            String provider = StringUtils.nvl(signVerifierResult.getProvider(), ""); // Kakao or Toss
            if (provider.indexOf("toss") > -1) {
                provider = "D";
            } else if (provider.indexOf("kakaotalk") > -1) {
                provider = "F";
            } else if (provider.indexOf("naver2") > -1) {
                provider = "G";
            } else if (provider.indexOf("pass") > -1) {
                provider = "H";
            }

            // ======================================================
            // 3. 본인인증때 추출된 CI 값과 사설인증서 검증서 CI 값 비교
            // ======================================================
            X509Certificate userCert = signVerifierResult.getSignerCertificate(); // 사용자인증서
            CertificateHelper certHelper = new CertificateHelper(userCert);
            String certSerial = StringUtils.nvl(certHelper.getSerialDecimal(), ""); // 사설인증서 시리얼 번호 추출

            if (StringUtils.isEmpty(certSerial) || StringUtils.isEmpty(provider)) {
                throw new PRCServiceException("PRCCMMVPCG_0010", "전달된 핀테크인증 전자서명 데이터 검증에 실패하였습니다.");
            }

            String userCI = StringUtils.defaultIfEmpty(SessionManager.getGlobalValue("USER_CI_INFO", String.class), "");
            log.debug("<<<<<<<<<<<<<<<<< authVerify USER_CI_INFO :: {}", userCI);

            /*
             * 개발계에서는 CI 값 비교를 할 수 없음
             * 카카오페이는 운영 APP으로 하기 때문
             * 토스는 SC은행과 CI 체계가 맞지 않음
             */
            boolean verifyUser = false;
            if (RunMode.PRD.equals(RuntimeContext.getRunMode())) {
                verifyUser = signVerifierResult.verifyCi(userCI);
            } else {
                log.debug("[RunMode={}]CI검증을 스킵했습니다", RuntimeContext.getRunMode());
                verifyUser = true;
            }

            if (!verifyUser)
                throw new PRCServiceException("PRCCMMVPCG_0005", "본인인증에 실패했습니다. 본인인증 사용자와 핀테크 인증서를 제출한 사용자가 다릅니다.");

            resultMap = new HashMap<String, Object>();
            resultMap.put("resultCode", "000");
            resultMap.put("provider", provider);
            resultMap.put("verifyCi", userCI);
            resultMap.put("certSerial", certSerial);
            resultMap.put("plainText", originSignedRawData);
            resultMap.put("pkcs7Data", pkcs7SignedData);

            log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 본인인증 검증 완료");

        } catch (DelfinoServiceException dse) {
            log.error("<<<<<<<<<<<<<<<<< authVerify ErrorCode :: {}", dse.getErrorCode());
            log.error("<<<<<<<<<<<<<<<<< authVerify ErrorMsg :: {}", dse.getErrorUserMessage());
            log.error("<<<<<<<<<<<<<<<<< authVerify ErrorMsg :: {}", dse.getMessage());

            if (dse.getVpcgProviderErrorInfo() != null) {
                com.wizvera.service.VpcgProviderErrorInfo vpcgError = dse.getVpcgProviderErrorInfo();
                log.error("<<<<<<<<<<<<<<<<< authVerify vpcgError ErrCode :: {}", vpcgError.getErrorCode());
                log.error("<<<<<<<<<<<<<<<<< authVerify vpcgError ErrMessage :: {}", vpcgError.getErrorMessage());
                log.error("<<<<<<<<<<<<<<<<< authVerify vpcgError ErrProvider :: {}", vpcgError.getProvider());

                throw new PRCServiceException(vpcgError.getErrorCode(), vpcgError.getErrorMessage());
            } else {
                String delfinoErrCode = Integer.toString(dse.getErrorCode());
                String delfinoErrMessage = "";

                delfinoErrMessage = LocaleContextHolder.getLocale().getLanguage().equalsIgnoreCase("ko") ? dse.getErrorUserMessage() : dse.getErrorUserMessage(com.wizvera.service.util.ErrorConvert.LOCALE_EN);
                throw new PRCServiceException(delfinoErrCode, delfinoErrMessage);
            }
        }

        return resultMap;
    }

    /**
     * 핀테크 로그인인증
     *
     * @param delfinoNonce
     * @param dataType     (L : 로그인, S : 전자서명, A : 본인인증)
     * @param vpcgData
     * @return
     * @throws PRCServiceException
     */
    @ComponentOperation(name = "핀테크 로그인인증", description = "핀테크 로그인인증", author = "이완주")
    public SignVerifierResult loginVerify(String delfinoNonce, String dataType, String vpcgData)
            throws PRCServiceException {
        log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 로그인 검증 시작");

        // 환경설정 경로 지정 필요할경우
        WizveraConfig delfinoConfig = null;
        try {
            delfinoConfig = new WizveraConfig(configPath);
        } catch (IOException|IllegalStateException e) {
            log.error("delfino.properties 설정파일 찾지 못해 기본생성자로 SignVerifier를 생성함");
        }

        SignVerifierResult signVerifierResult = null; // 서명검증 결과 객체 (Veraport-CG LIB)

        if (dataType == null || "".equalsIgnoreCase(dataType) || !"L".equalsIgnoreCase(dataType))
            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다.");

        if (vpcgData == null || "".equalsIgnoreCase(vpcgData))
            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다.");

        log.debug("<<<<<<<<<<<<<<<<< loginVerify dataType={}", dataType);
        log.debug("<<<<<<<<<<<<<<<<< loginVerify vpcgData={}", vpcgData);
        log.debug("<<<<<<<<<<<<<<<<< loginVerify delfinoNonce {} ", delfinoNonce);

        try {
            SignVerifier signVerifier = new SignVerifier(delfinoConfig); // 서명검증 객체 (Veraport-CG LIB)

            signVerifierResult = signVerifier.verifyPKCS7WithNonce(vpcgData, delfinoNonce,
                    SignVerifier.CERT_STATUS_CHECK_TYPE_NONE);

            log.debug("<<<<<<<<<<<<<<<<< loginVerify getProvider :: {}", signVerifierResult.getProvider());
            log.debug("<<<<<<<<<<<<<<<<< loginVerify getPKCS7SignedData :: {}",
                    signVerifierResult.getPKCS7SignedData());
            log.debug("<<<<<<<<<<<<<<<<< loginVerify getSignedRawData :: {}", signVerifierResult.getSignedRawData());

            String pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
            String signedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터

            if (StringUtils.isEmpty(signedRawData) || StringUtils.isEmpty(pkcs7SignedData)) {
                throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
            }

        } catch (DelfinoServiceException dse) {
            log.error("<<<<<<<<<<<<<<<<< loginVerify ErrorCode :: {}", dse.getErrorCode());
            log.error("<<<<<<<<<<<<<<<<< loginVerify ErrorMsg :: {}", dse.getErrorUserMessage());
            log.error("<<<<<<<<<<<<<<<<< loginVerify  ErrorMsg :: {}", dse.getMessage());

            if (dse.getVpcgProviderErrorInfo() != null) {
                com.wizvera.service.VpcgProviderErrorInfo vpcgError = dse.getVpcgProviderErrorInfo();
                log.error("<<<<<<<<<<<<<<<<< loginVerify vpcgError ErrCode :: {}", vpcgError.getErrorCode());
                log.error("<<<<<<<<<<<<<<<<< loginVerify vpcgError ErrMessage :: {}", vpcgError.getErrorMessage());
                log.error("<<<<<<<<<<<<<<<<< loginVerify vpcgError ErrProvider :: {}", vpcgError.getProvider());

                throw new PRCServiceException(vpcgError.getErrorCode(), vpcgError.getErrorMessage());
            } else {
                String delfinoErrCode = Integer.toString(dse.getErrorCode());
                String delfinoErrMessage = "";

                delfinoErrMessage = LocaleContextHolder.getLocale().getLanguage().equalsIgnoreCase("ko") ? dse.getErrorUserMessage() : dse.getErrorUserMessage(com.wizvera.service.util.ErrorConvert.LOCALE_EN);

                throw new PRCServiceException(delfinoErrCode, delfinoErrMessage);
            }
        }

        log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 로그인 검증 완료");
        return signVerifierResult;
    }

    /**
     * 핀테크 전자서명 검증
     *
     * @param dataType   (L : 로그인, S : 전자서명, A : 본인인증)
     * @param verifyData
     * @param vpcgData
     * @return
     * @throws PRCServiceException
     */
    @ComponentOperation(name = "핀테크 전자서명 검증", description = "핀테크 전자서명 검증", author = "이완주")
    public HashMap<String, Object> signVerify(String dataType, String verifyData, String vpcgData)
            throws PRCServiceException {

        // 환경설정 경로 지정 필요할경우
        WizveraConfig delfinoConfig = null;
        try {
            delfinoConfig = new WizveraConfig(configPath);
        } catch (IOException|IllegalStateException e) {
            log.error("delfino.properties 설정파일 찾지 못해 기본생성자로 SignVerifier를 생성함");
        }

        HashMap<String, Object> resultMap = null;

        String orgUserCi = null;
        String orgSerial = null;
        String orgProvider = null;
        String UserId = null;

        try {
            // ======================================================
            // 1. provider 확인
            // ======================================================
            JSONObject jVpcgObj = new JSONObject(vpcgData);
            if (SessionManager.isLogin()) { // 로그인인경우 로그인세션에서 , 비로그인인경우에는 글로벌 세션에서 가져오자.
                orgUserCi = StringUtils
                        .defaultIfEmpty(SessionManager.getLoginValue("FINCERT_VERIFIER_CINO", String.class), "");
                orgSerial = StringUtils
                        .defaultIfEmpty(SessionManager.getLoginValue("FINCERT_VERIFIER_SERIAL", String.class), "");
                orgProvider = StringUtils
                        .defaultIfEmpty(SessionManager.getLoginValue("FINCERT_VERIFIER_TYPE", String.class), "");
                UserId = StringUtils.defaultIfEmpty(SessionManager.getLoginValue("UserID", String.class), "");
            } else {
                orgUserCi = StringUtils
                        .defaultIfEmpty(SessionManager.getGlobalValue("FINCERT_VERIFIER_CINO", String.class), "");
                orgSerial = StringUtils
                        .defaultIfEmpty(SessionManager.getGlobalValue("FINCERT_VERIFIER_SERIAL", String.class), "");
                orgProvider = StringUtils
                        .defaultIfEmpty(SessionManager.getGlobalValue("FINCERT_VERIFIER_TYPE", String.class), "");
                UserId = StringUtils.defaultIfEmpty(SessionManager.getGlobalValue("UserID", String.class), "");
            }

            if (orgProvider.indexOf("toss") > -1) {
                orgProvider = "D";
            } else if (orgProvider.indexOf("kakaotalk") > -1) {
                orgProvider = "F";
            } else if (orgProvider.indexOf("naver2") > -1) {
                orgProvider = "G";
            } else if (orgProvider.indexOf("pass") > -1) {
                orgProvider = "H";
            }

            String signData = StringUtils.defaultIfEmpty((String) jVpcgObj.get("signData"), "");
            // String logServiceCode = ""; // 로그용 서비스코드 => 필요없는 것 같음

            log.debug("<<<<<<<<<<<<<<<<< signVerify orgUserCi :: {}", orgUserCi);
            log.debug("<<<<<<<<<<<<<<<<< signVerify orgSerial :: {}", orgSerial);
            log.debug("<<<<<<<<<<<<<<<<< signVerify signData :: {}", signData);

            if (orgUserCi == null || "".equalsIgnoreCase(orgUserCi)
                    || orgSerial == null || "".equalsIgnoreCase(orgSerial)
                    || signData == null || "".equalsIgnoreCase(signData)
                    || orgProvider == null || "".equalsIgnoreCase(orgProvider)) {
                throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다.");
            }

        } catch (Exception pe) {
        	log.error(pe.getMessage());
            throw new PRCServiceException("PRCCMMVPCG_0001", "핀테크인증 요청 정보가 잘못되었습니다. 다시 거래해 주시기 바랍니다.");
        }

        try {
            // ======================================================
            // 2. 서명데이터 검증
            // ======================================================
            SignVerifier signVerifier = new SignVerifier(delfinoConfig); // 서명검증 객체
            SignVerifierResult signVerifierResult = signVerifier.verifyPKCS7(vpcgData,
                    SignVerifier.CERT_STATUS_CHECK_TYPE_NONE);// 서명검증 결과

            log.debug("<<<<<<<<<<<<<<<<< signVerify getProvider :: {}", signVerifierResult.getProvider());
            log.debug("<<<<<<<<<<<<<<<<< signVerify getPKCS7SignedData :: {}", signVerifierResult.getPKCS7SignedData());
            log.debug("<<<<<<<<<<<<<<<<< signVerify getSignedRawData :: {}", signVerifierResult.getSignedRawData());
            log.debug("<<<<<<<<<<<<<<<<< signVerify getOriginSignedRawData :: {}",
                    signVerifierResult.getOriginSignedRawData());

            String pkcs7SignedData = signVerifierResult.getPKCS7SignedData(); // PKCS7 데이터
            String signedRawData = signVerifierResult.getOriginSignedRawData(); // 원본 전자서명 데이터

            if (StringUtils.isEmpty(signedRawData) || StringUtils.isEmpty(pkcs7SignedData)) {
                throw new PRCServiceException("PRCCMMVPCG_0002", "핀테크인증 전자서명 데이터가 존재하지 않습니다. 다시 거래해 주시기 바랍니다.");
            }

            X509Certificate userCert = signVerifierResult.getSignerCertificate(); // 사용자인증서 정보
            if (userCert == null) {
                throw new PRCServiceException("PRCCMMVPCG_0010", "전달된 핀테크인증 전자서명 데이터 검증에 실패하였습니다.");
            }

            String provider = StringUtils.nvl(signVerifierResult.getProvider(), ""); // Kakao or Toss
            if (provider.indexOf("toss") > -1) {
                provider = "D";
            } else if (provider.indexOf("kakaotalk") > -1) {
                provider = "F";
            } else if (provider.indexOf("naver2") > -1) {
                provider = "G";
            } else if (provider.indexOf("pass") > -1) {
                provider = "H";
            }

            if (dataType != null && (dataType.toUpperCase()).equalsIgnoreCase("S")) {
                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 signVerify 서명검증 시작");

                log.debug("<<<<<<<<<<<<<<<<< signVerify orgUserCi :: {}", orgUserCi);
                log.debug("<<<<<<<<<<<<<<<<< signVerify orgSerial :: {}", orgSerial);
                log.debug("<<<<<<<<<<<<<<<<< signVerify orgProvider :: {}", orgProvider);
                log.debug("<<<<<<<<<<<<<<<<< signVerify provider :: {}", provider);

                // 획득한 인증서로 도우미 생성
                CertificateHelper certHelper = new CertificateHelper(userCert);
                String certSerial = certHelper.getSerialDecimal();

                if (!orgProvider.equalsIgnoreCase(provider))
                    throw new PRCServiceException("PRCCMMVPCG_0006", "본인인증에 실패했습니다. 로그인 사용자와 핀테크 인증서를 제출한 사용자가 다릅니다.");

                if (!orgSerial.equalsIgnoreCase(certSerial)) {
                    resultMap = new HashMap<String, Object>();
                    resultMap.put("resultCode", "999");
                    return resultMap;
                }

                String NTBSignSSN = SessionManager.getGlobalValue("NOTLOGINSSN", String.class); // NTB 전자서명시 본인인증 체크 로직
                log.debug("<<<<<<<<<<<<<<<<< signVerify NOTLOGINSSN :: {}", NTBSignSSN);

                // 서명원문 데이터를 Encode 했는지 확인하고 안했다면 Sever에서 Decode 할필요 없음
                String orgSignData = "";
                orgSignData = signVerifierResult.getSignedRawData(); // 서명 원본 데이터
                log.debug("<<<<<<<<<<<<<<<<< signVerify orgSignData :: {}", orgSignData);
                orgSignData = java.net.URLDecoder.decode(signVerifierResult.getSignedRawData()); // 서명 원본데이터 저장
                log.debug("<<<<<<<<<<<<<<<<< signVerify orgSignData decode :: {}", orgSignData);

                SessionManager.setGlobalValue(PRCSharedConstants.SIGN_ORG_DATA_NAME, orgSignData);
                SessionManager.setGlobalValue(PRCSharedConstants.SIGN_DATA_NAME, pkcs7SignedData);

                java.util.Date currentTime = new java.util.Date();// 현재 시간
                int dateformat = (int) ((userCert.getNotAfter().getTime() - currentTime.getTime())
                        / (24 * 60 * 60 * 1000));

                log.debug("<<<<<<<<<<<<<<<<< signVerify dateformat :: {}", Integer.toString(dateformat));
                log.debug("<<<<<<<<<<<<<<<<< signVerify provider :: {}", provider);
                log.debug("<<<<<<<<<<<<<<<<< signVerify certSerial :: {}", certSerial);
                log.debug("<<<<<<<<<<<<<<<<< signVerify pkcs7SignedData :: {}", pkcs7SignedData);

                resultMap = new HashMap<String, Object>();
                resultMap.put("resultCode", "000");
                resultMap.put("provider", provider);
                resultMap.put("certSerial", certSerial);
                resultMap.put("signText", orgSignData);
                resultMap.put("pkcs7Data", pkcs7SignedData);

                log.debug("<<<<<<<<<<<<<<<<< 핀테크인증서 signVerify 서명검증 완료");

            }

        } catch (DelfinoServiceException dse) {
            log.error("<<<<<<<<<<<<<<<<< signVerify ErrorCode :: {}", dse.getErrorCode());
            log.error("<<<<<<<<<<<<<<<<< signVerify ErrorMsg :: {}", dse.getErrorUserMessage());
            log.error("<<<<<<<<<<<<<<<<< signVerify  ErrorMsg :: {}", dse.getMessage());

            if (dse.getVpcgProviderErrorInfo() != null) {
                com.wizvera.service.VpcgProviderErrorInfo vpcgError = dse.getVpcgProviderErrorInfo();
                log.error("<<<<<<<<<<<<<<<<< signVerify vpcgError ErrCode :: {}", vpcgError.getErrorCode());
                log.error("<<<<<<<<<<<<<<<<< signVerify vpcgError ErrMessage :: {}", vpcgError.getErrorMessage());
                log.error("<<<<<<<<<<<<<<<<< signVerify vpcgError ErrProvider :: {}", vpcgError.getProvider());

                throw new PRCServiceException(vpcgError.getErrorCode(), vpcgError.getErrorMessage());
            } else {
                String delfinoErrCode = Integer.toString(dse.getErrorCode());
                String delfinoErrMessage = "";

                delfinoErrMessage = LocaleContextHolder.getLocale().getLanguage().equalsIgnoreCase("ko") ? dse.getErrorUserMessage() : dse.getErrorUserMessage(com.wizvera.service.util.ErrorConvert.LOCALE_EN);

                throw new PRCServiceException(delfinoErrCode, delfinoErrMessage);
            }
        }

        return resultMap;
    }

}
